import React, { useState } from 'react';
import { useDispatch } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import { loginUser, registerUser } from '../api/authApi';
import { setUser } from '../redux/actions/authActions';

const LoginPage = () => {
  const [isReg, setIsReg] = useState(false);
  const [form, setForm] = useState({ username: '', password: '' });
  const dispatch = useDispatch();
  const navigate = useNavigate();

  const normalizeUser = (data) => ({
    id: data.id || Date.now(),
    username: data.username || form.username,
    role: data.role || 'user'
  });

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      const data = isReg ? await registerUser(form) : await loginUser(form);
      dispatch(setUser(normalizeUser(data)));
      toast.success(isReg ? 'Registration completed successfully.' : 'You are logged in.');
      navigate('/');
    } catch (err) {
      const fallbackRole = form.username.trim().toLowerCase() === 'admin' ? 'admin' : 'user';

      dispatch(
        setUser({
          id: Date.now(),
          username: form.username,
          role: fallbackRole
        })
      );

      toast.info(
        isReg
          ? 'Server is unavailable. Demo registration is saved locally.'
          : 'Server is unavailable. Demo login is saved locally.'
      );
      navigate('/');
    }
  };

  return (
    <div className="auth-box">
      <h2 className="auth-title">{isReg ? 'РЎРѕР·РґР°С‚СЊ Р°РєРєР°СѓРЅС‚' : 'РђРІС‚РѕСЂРёР·Р°С†РёСЏ'}</h2>

      <form onSubmit={handleSubmit} className="auth-form">
        <input
          type="text"
          placeholder="Р›РѕРіРёРЅ"
          required
          value={form.username}
          onChange={(e) => setForm({ ...form, username: e.target.value })}
        />
        <input
          type="password"
          placeholder="РџР°СЂРѕР»СЊ"
          required
          value={form.password}
          onChange={(e) => setForm({ ...form, password: e.target.value })}
        />
        <button type="submit" className="button">
          {isReg ? 'Р—Р°СЂРµРіРёСЃС‚СЂРёСЂРѕРІР°С‚СЊСЃСЏ' : 'Р’РѕР№С‚Рё'}
        </button>
      </form>

      <p className="auth-switch" onClick={() => setIsReg(!isReg)}>
        {isReg ? 'РЈР¶Рµ РµСЃС‚СЊ РїСЂРѕС„РёР»СЊ? Р’РѕР№С‚Рё' : 'РќРµС‚ Р°РєРєР°СѓРЅС‚Р°? Р РµРіРёСЃС‚СЂР°С†РёСЏ'}
      </p>
    </div>
  );
};

export default LoginPage;
